function getToolKey(pathname) {
  if (!pathname) return 'calorie';
  const p = pathname.replace(/^\/[a-z]{2}(\/|$)/, '/').replace(/\/$/, '');
        const toolMap = { '/age': 'age', '/autoloan': 'autoloan', '/average': 'average', '/bmi': 'bmi', '/bodyfat': 'bodyfat', '/cagr': 'cagr', '/calorieburn': 'calorieburn', '/coinflip': 'coinflip', '/compound': 'compound', '/convert': 'convert', '/currency': 'currency', '/date': 'date', '/daysuntil': 'daysuntil', '/dice': 'dice', '/discount': 'discount', '/duedate': 'duedate', '/duration': 'duration', '/emi': 'emi', '/fraction': 'fraction', '/fuelcost': 'fuelcost', '/gpa': 'gpa', '/grade': 'grade', '/idealweight': 'idealweight', '/investment': 'investment', '/loan': 'loan', '/lotto': 'lotto', '/love': 'love', '/markup': 'markup', '/mortgage': 'mortgage', '/ohm': 'ohm', '/overtime': 'overtime', '/ovulation': 'ovulation', '/pace': 'pace', '/password': 'password', '/pdf': 'pdf', '/percent': 'percent', '/period': 'period', '/petage': 'petage', '/photo': 'photo', '/pregnancy': 'pregnancy', '/privacy': 'privacy', '/qr': 'qr', '/random': 'random', '/ratio': 'ratio', '/retirement': 'retirement', '/salary': 'salary', '/salestax': 'salestax', '/simpleinterest': 'simpleinterest', '/sip': 'sip', '/sleep': 'sleep', '/speed': 'speed', '/sqft': 'sqft', '/tdee': 'tdee', '/text': 'text', '/timer': 'timer', '/tip': 'tip', '/vat': 'vat', '/waterintake': 'waterintake', '/wordcounter': 'wordcounter' };
  return toolMap[p] || 'calorie';  // calorie is default landing page
}

export default async function LocaleLayout({ children, params }) {
  const { locale } = await params;
  const messages = await getMessages();
  const headersList = await headers();
  const pathname = headersList.get('x-pathname') || headersList.get('x-url') || '';
  const toolKey = getToolKey(pathname);
  const t = tools[locale] || tools.en;
  const tool = t[toolKey] || t.calorie;

  const schemaJson = JSON.stringify({
    "@context": "https://schema.org",
    "@type": "SoftwareApplication",
    name: tool.name,
    description: tool.desc,
    applicationCategory: tool.cat,
    operatingSystem: "Web",
    browserRequirements: "Requires JavaScript",
    offers: {
      "@type": "Offer",
      price: "0",
      priceCurrency: "USD",
    },
    author: {
      "@type": "Organization",
      name: "hello-tools",
      url: "https://oxoxox1.com",
    },
  });

  return (
    <html lang={locale} className="h-full antialiased">
      <head>
        <script
          async
          src={`https://pagead2.googlesyndication.com/pagead/js/adsbygoogle.js?client=ca-pub-8178172082493004`}
          crossOrigin="anonymous"
        />
        <script
          type="application/ld+json"
          dangerouslySetInnerHTML={{ __html: schemaJson }}
          suppressHydrationWarning
        />
      </head>
      <body className="min-h-full flex flex-col" style={{ background: 'var(--os9-bg)' }}>
        <NextIntlClientProvider locale={locale} messages={messages}>
          {children}
        </NextIntlClientProvider>
        <Analytics />
        <script dangerouslySetInnerHTML={{
          __html: `(adsbygoogle = window.adsbygoogle || []).push({});`
        }} />
      </body>
    </html>
  );
}